];

export const CheckIcon = () => (
  <svg className="w-6 h-6 text-green-500 mr-2 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
  </svg>
);

export const WarningIcon = () => (
  <svg className="w-8 h-8 text-red-500 mr-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
  </svg>
);

import React, { useState } from 'react';
import { PRICE_DISCOUNT, PIX_KEY } from '../constants';
import { PaymentMethod, Order } from '../types';

interface CheckoutProps {
  onSuccess: (order: Order) => void;
  onCancel: () => void;
}

const Checkout: React.FC<CheckoutProps> = ({ onSuccess, onCancel }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [method, setMethod] = useState<PaymentMethod>('PIX');
  const [form, setForm] = useState({ name: '', email: '', phone: '' });

  const handleNext = (e: React.FormEvent) => {
    e.preventDefault();
    setStep(2);
  };

  const finishPayment = () => {
    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9).toUpperCase(),
      customerName: form.name,
      customerEmail: form.email,
      customerPhone: form.phone,
      amount: PRICE_DISCOUNT,
      method: method,
      status: method === 'PAGBANK' ? 'PAID' : 'PENDING',
      date: new Date().toLocaleString('pt-BR'),
    };

    const existing = JSON.parse(localStorage.getItem('orders') || '[]');
    localStorage.setItem('orders', JSON.stringify([...existing, newOrder]));
    onSuccess(newOrder);
  };

  return (
    <div className="fixed inset-0 bg-slate-900/90 z-[200] flex items-center justify-center p-4">
      <div className="bg-white w-full max-w-xl rounded-3xl overflow-hidden shadow-2xl">
        <div className="bg-blue-600 p-6 text-white flex justify-between items-center">
          <h2 className="text-xl font-bold">Checkout Seguro</h2>
          <button onClick={onCancel} className="text-white/80 hover:text-white">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="p-8">
          {step === 1 ? (
            <form onSubmit={handleNext} className="space-y-4">
              <h3 className="text-lg font-bold mb-4">Informações de Contato</h3>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Nome Completo</label>
                <input required type="text" className="w-full border rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none" 
                  value={form.name} onChange={e => setForm({...form, name: e.target.value})} />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Seu melhor E-mail</label>
                <input required type="email" className="w-full border rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={form.email} onChange={e => setForm({...form, email: e.target.value})} />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">WhatsApp</label>
                <input required type="tel" placeholder="(00) 00000-0000" className="w-full border rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={form.phone} onChange={e => setForm({...form, phone: e.target.value})} />
              </div>
              <button type="submit" className="w-full bg-blue-600 text-white font-bold py-4 rounded-xl hover:bg-blue-700 transition-all">
                IR PARA O PAGAMENTO
              </button>
            </form>
          ) : (
            <div className="space-y-6">
              <h3 className="text-lg font-bold">Forma de Pagamento</h3>

              <div className="grid grid-cols-2 gap-4">
                <button onClick={() => setMethod('PIX')} className={`p-4 border-2 rounded-2xl flex flex-col items-center gap-2 transition-all ${method === 'PIX' ? 'border-blue-600 bg-blue-50' : 'border-gray-100 hover:border-gray-200'}`}>
                  <span className="text-2xl">⚡</span>
                  <span className="font-bold">PIX Direto</span>
                </button>
                <button onClick={() => setMethod('PAGBANK')} className={`p-4 border-2 rounded-2xl flex flex-col items-center gap-2 transition-all ${method === 'PAGBANK' ? 'border-blue-600 bg-blue-50' : 'border-gray-100 hover:border-gray-200'}`}>
                  <span className="text-2xl">💳</span>
                  <span className="font-bold">PagBank</span>
                </button>
              </div>

              {method === 'PIX' ? (
                <div className="bg-slate-50 p-6 rounded-2xl text-center">
                  <p className="text-sm text-gray-500 mb-4">Escaneie o QR Code ou copie a chave:</p>
                  <div className="w-40 h-40 bg-gray-200 mx-auto mb-4 flex items-center justify-center text-gray-400 text-xs">
                    [QR CODE SIMULADO]
                  </div>
                  <div className="bg-white border p-3 rounded-lg flex items-center justify-between mb-4">
                    <span className="text-xs font-mono truncate mr-2">{PIX_KEY}</span>
                    <button onClick={() => navigator.clipboard.writeText(PIX_KEY)} className="text-blue-600 text-xs font-bold uppercase">Copiar</button>
                  </div>
                  <p className="text-[10px] text-gray-400">Após pagar via PIX, aguarde a validação manual pelo administrador.</p>
                </div>
              ) : (
                <div className="bg-slate-50 p-6 rounded-2xl text-center">
                  <p className="text-sm text-gray-600">Ao clicar no botão abaixo, você será redirecionado para o ambiente seguro do PagBank.</p>
                </div>
              )}

              <div className="flex gap-4">
                <button onClick={() => setStep(1)} className="flex-1 bg-gray-100 text-gray-600 font-bold py-4 rounded-xl">VOLTAR</button>
                <button onClick={finishPayment} className="flex-[2] bg-green-600 text-white font-bold py-4 rounded-xl hover:bg-green-700 shadow-lg shadow-green-600/20">
                  {method === 'PIX' ? 'JÁ REALIZEI O PIX' : 'PAGAR COM PAGBANK'}
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Checkout;

import React, { useState, useEffect } from 'react';
import { Order } from '../types';
import { PRODUCT_LINK } from '../constants';

const Dashboard: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [filter, setFilter] = useState<string>('ALL');

  useEffect(() => {
    const data = JSON.parse(localStorage.getItem('orders') || '[]');
    setOrders(data);
  }, []);

  const updateStatus = (id: string, status: Order['status']) => {
    const updated = orders.map(o => o.id === id ? { ...o, status } : o);
    setOrders(updated);
    localStorage.setItem('orders', JSON.stringify(updated));
  };

  const sendWhatsApp = (order: Order) => {
    const message = `Olá ${order.customerName}! Recebemos seu pagamento do Guia de Aluguéis 2026. Aqui está seu acesso: ${PRODUCT_LINK}`;
    const url = `https://wa.me/55${order.customerPhone.replace(/\D/g,'')}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
    updateStatus(order.id, 'SENT');
  };

  const sendEmail = (order: Order) => {
    const subject = "Seu Guia de Aluguéis 2026 Chegou!";
    const body = `Olá ${order.customerName},\n\nObrigado por adquirir o nosso guia. Você acaba de dar um grande passo para proteger seu patrimônio.\n\nClique aqui para baixar seu guia: ${PRODUCT_LINK}\n\nQualquer dúvida, responda este e-mail.`;
    window.location.href = `mailto:${order.customerEmail}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    updateStatus(order.id, 'SENT');
  };

  const filteredOrders = orders.filter(o => filter === 'ALL' ? true : o.status === filter);

  return (
    <div className="min-h-screen bg-slate-50">
      <nav className="bg-slate-900 text-white p-4 flex justify-between items-center px-8">
        <h1 className="font-bold text-xl">Dashboard Administrativo</h1>
        <button onClick={onClose} className="bg-white/10 px-4 py-2 rounded-lg text-sm hover:bg-white/20">Sair</button>
      </nav>

      <main className="max-w-7xl mx-auto p-8">
        <div className="flex justify-between items-center mb-8">
          <h2 className="text-2xl font-bold">Vendas e Pedidos</h2>
          <div className="flex gap-2">
            {['ALL', 'PENDING', 'PAID', 'SENT'].map(f => (
              <button key={f} onClick={() => setFilter(f)} 
                className={`px-4 py-2 rounded-full text-xs font-bold ${filter === f ? 'bg-blue-600 text-white' : 'bg-white border text-gray-600'}`}>
                {f === 'ALL' ? 'Todos' : f === 'PENDING' ? 'Pendentes' : f === 'PAID' ? 'Pagos' : 'Enviados'}
              </button>
            ))}
          </div>
        </div>

        <div className="bg-white rounded-2xl shadow-sm border overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-gray-50 border-b">
              <tr>
                <th className="p-4 text-sm font-bold text-gray-500">ID / Data</th>
                <th className="p-4 text-sm font-bold text-gray-500">Cliente</th>
                <th className="p-4 text-sm font-bold text-gray-500">Valor / Método</th>
                <th className="p-4 text-sm font-bold text-gray-500">Status</th>
                <th className="p-4 text-sm font-bold text-gray-500 text-right">Ações de Entrega</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {filteredOrders.length === 0 ? (
                <tr><td colSpan={5} className="p-20 text-center text-gray-400">Nenhum pedido encontrado.</td></tr>
              ) : filteredOrders.map(order => (
                <tr key={order.id} className="hover:bg-gray-50 transition-colors">
                  <td className="p-4">
                    <span className="block font-mono text-xs font-bold text-blue-600">#{order.id}</span>
                    <span className="text-[10px] text-gray-400">{order.date}</span>
                  </td>
                  <td className="p-4">
                    <span className="block font-bold">{order.customerName}</span>
                    <span className="text-xs text-gray-500">{order.customerEmail}</span>
                  </td>
                  <td className="p-4">
                    <span className="block font-bold">{order.amount}</span>
                    <span className={`text-[10px] px-2 py-0.5 rounded-full ${order.method === 'PIX' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>{order.method}</span>
                  </td>
                  <td className="p-4">
                    <select 
                      value={order.status} 
                      onChange={(e) => updateStatus(order.id, e.target.value as any)}
                      className={`text-xs font-bold border-none rounded-lg p-1 ${order.status === 'PAID' ? 'bg-green-100 text-green-700' : order.status === 'SENT' ? 'bg-blue-100 text-blue-700' : 'bg-yellow-100 text-yellow-700'}`}
                    >
                      <option value="PENDING">Pendente</option>
                      <option value="PAID">Pago</option>
                      <option value="SENT">Enviado</option>
                    </select>
                  </td>
                  <td className="p-4 text-right">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => sendWhatsApp(order)} title="Enviar via WhatsApp" className="p-2 bg-green-500 text-white rounded-lg hover:bg-green-600">
