          ) : (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
              <div className="flex justify-between items-start border-b pb-4">
                <div>
                  <p className="text-[10px] text-slate-400 uppercase font-bold tracking-widest">Status do Pedido</p>
                  <div className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-black mt-1 ${
                    foundOrder.status === 'PAID' || foundOrder.status === 'SENT' ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'
                  }`}>
