                    <img src={settings.pixQrCode} className="w-32 h-32 mx-auto rounded-xl shadow-sm border bg-white p-2" alt="PIX" />
                  )}
                  <div className="bg-white p-3 rounded-xl border flex items-center justify-between">
                    <span className="text-[10px] font-mono truncate mr-2">{settings.pixKey}</span>
