import React, { useState, useEffect } from 'react';
import { Order, PaymentSettings } from '../types';
import { PRODUCT_LINK, PIX_KEY } from '../constants';

const Dashboard: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [activeTab, setActiveTab] = useState<'ORDERS' | 'SETTINGS'>('ORDERS');
  const [orders, setOrders] = useState<Order[]>([]);
  const [filter, setFilter] = useState<string>('ALL');
  const [isSendingEmail, setIsSendingEmail] = useState<string | null>(null);

  const [settings, setSettings] = useState<PaymentSettings>({
    pagbankEnabled: true,
    pixEnabled: true,
    apiKey: '',
    pixKey: PIX_KEY,
    pixQrCode: '',
    emailEnabled: false,
    emailServiceId: '',
    emailTemplateId: '',
    emailPublicKey: '',
    ebookFileData: '',
    ebookFileName: ''
  });

  useEffect(() => {
    const data = JSON.parse(localStorage.getItem('orders') || '[]');
    setOrders(data);

    const savedSettings = localStorage.getItem('payment_settings');
    if (savedSettings) {
      setSettings(JSON.parse(savedSettings));
    }
  }, []);

  const saveSettings = () => {
    localStorage.setItem('payment_settings', JSON.stringify(settings));
    alert('Configurações salvas com sucesso!');
  };

  const handleEbookUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSettings({
          ...settings,
          ebookFileData: reader.result as string,
          ebookFileName: file.name
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const updateStatus = (id: string, status: Order['status']) => {
    const updated = orders.map(o => o.id === id ? { ...o, status } : o);
    setOrders(updated);
    localStorage.setItem('orders', JSON.stringify(updated));
  };

  const sendWhatsApp = (order: Order) => {
    const message = `Olá ${order.customerName}! Seu Guia de Aluguéis está disponível. Acesse o site e use seu código #${order.id} para baixar.`;
    const url = `https://wa.me/55${order.customerPhone.replace(/\D/g,'')}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
    updateStatus(order.id, 'SENT');
  };

  const sendEmail = async (order: Order) => {
    if (!settings.emailEnabled || !settings.emailServiceId) {
      alert("Configure o serviço de e-mail nas configurações primeiro!");
      return;
    }

    setIsSendingEmail(order.id);
    const templateParams = {
      to_name: order.customerName,
      to_email: order.customerEmail,
      order_id: order.id,
      download_link: window.location.origin // Link para o site onde ele rastreia
    };

    try {
      const response = await fetch('https://api.emailjs.com/api/v1.0/email/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          service_id: settings.emailServiceId,
          template_id: settings.emailTemplateId,
          user_id: settings.emailPublicKey,
          template_params: templateParams
        })
      });

      if (response.ok) {
        alert(`E-mail enviado!`);
        updateStatus(order.id, 'SENT');
      } else {
        throw new Error('Erro');
      }
    } catch (error) {
      alert("Erro ao enviar e-mail.");
    } finally {
      setIsSendingEmail(null);
    }
  };

  const filteredOrders = orders.filter(o => filter === 'ALL' ? true : o.status === filter);

  return (
    <div className="min-h-screen bg-slate-50">
      <nav className="bg-slate-900 text-white p-4 flex justify-between items-center px-8 shadow-lg">
        <div className="flex items-center gap-8">
          <h1 className="font-bold text-xl flex items-center gap-2">ADMIN</h1>
          <div className="flex gap-1">
            <button onClick={() => setActiveTab('ORDERS')} className={`px-4 py-2 rounded-lg text-sm font-bold ${activeTab === 'ORDERS' ? 'bg-blue-600' : ''}`}>Vendas</button>
            <button onClick={() => setActiveTab('SETTINGS')} className={`px-4 py-2 rounded-lg text-sm font-bold ${activeTab === 'SETTINGS' ? 'bg-blue-600' : ''}`}>Configurações</button>
          </div>
        </div>
        <button onClick={onClose} className="bg-red-500 text-white px-4 py-2 rounded-lg text-sm font-bold">Sair</button>
      </nav>

      <main className="max-w-7xl mx-auto p-8">
        {activeTab === 'ORDERS' ? (
          <div className="bg-white rounded-3xl shadow-sm border overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-slate-50 border-b">
                <tr>
                  <th className="p-4 text-xs font-bold uppercase">Pedido</th>
                  <th className="p-4 text-xs font-bold uppercase">Cliente</th>
                  <th className="p-4 text-xs font-bold uppercase">Status</th>
                  <th className="p-4 text-xs font-bold uppercase text-right">Ações</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {filteredOrders.map(order => (
                  <tr key={order.id}>
                    <td className="p-4 font-mono text-xs font-bold">#{order.id}</td>
                    <td className="p-4">
                      <div className="font-bold">{order.customerName}</div>
                      <div className="text-xs text-gray-400">{order.customerEmail}</div>
                    </td>
                    <td className="p-4">
                      <select value={order.status} onChange={(e) => updateStatus(order.id, e.target.value as any)} className="text-xs border rounded p-1">
                        <option value="PENDING">Pendente</option>
                        <option value="PAID">Pago</option>
                        <option value="SENT">Enviado</option>
                      </select>
                    </td>
                    <td className="p-4 text-right flex justify-end gap-2">
                      <button onClick={() => sendWhatsApp(order)} className="p-2 bg-green-500 text-white rounded-lg">WA</button>
                      <button onClick={() => sendEmail(order)} className="p-2 bg-blue-500 text-white rounded-lg">Email</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="max-w-4xl mx-auto space-y-6">
            <section className="bg-white p-6 rounded-2xl border">
              <h3 className="font-bold mb-4">Meios de Pagamento (Original)</h3>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-xs font-bold text-gray-400">CHAVE PIX</label>
                  <input type="text" value={settings.pixKey} onChange={e => setSettings({...settings, pixKey: e.target.value})} className="w-full border rounded p-2 text-sm" />
                </div>
                <div>
                  <label className="text-xs font-bold text-gray-400">PAGBANK API KEY</label>
                  <input type="text" value={settings.apiKey} onChange={e => setSettings({...settings, apiKey: e.target.value})} className="w-full border rounded p-2 text-sm" />
                </div>
              </div>
            </section>

            <section className="bg-white p-6 rounded-2xl border">
              <h3 className="font-bold mb-4">Atualizar E-book / Guia PDF</h3>
              <div className="flex items-center gap-4">
                <input type="file" accept=".pdf,.epub" onChange={handleEbookUpload} className="hidden" id="ebook-upload" />
                <label htmlFor="ebook-upload" className="cursor-pointer bg-slate-900 text-white px-6 py-3 rounded-xl font-bold text-sm">SELECIONAR NOVO ARQUIVO</label>
                {settings.ebookFileName && (
                  <div className="text-sm text-green-600 font-bold flex items-center gap-2">
                    ✓ {settings.ebookFileName} carregado
                  </div>
                )}
              </div>
              <p className="text-[10px] text-gray-400 mt-2">O arquivo selecionado será o mesmo que aparecerá no "Pendrive Virtual" do cliente.</p>
            </section>

            <section className="bg-white p-6 rounded-2xl border">
              <h3 className="font-bold mb-4">Configuração de E-mail (EmailJS)</h3>
              <div className="grid grid-cols-3 gap-4">
                <input type="text" placeholder="Service ID" value={settings.emailServiceId} onChange={e => setSettings({...settings, emailServiceId: e.target.value})} className="border rounded p-2 text-xs" />
                <input type="text" placeholder="Template ID" value={settings.emailTemplateId} onChange={e => setSettings({...settings, emailTemplateId: e.target.value})} className="border rounded p-2 text-xs" />
                <input type="text" placeholder="Public Key" value={settings.emailPublicKey} onChange={e => setSettings({...settings, emailPublicKey: e.target.value})} className="border rounded p-2 text-xs" />
              </div>
            </section>

            <button onClick={saveSettings} className="w-full bg-blue-600 text-white font-bold py-4 rounded-xl shadow-lg">SALVAR TUDO</button>
          </div>
        )}
      </main>
    </div>
  );
};

export default Dashboard;

