        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600 mx-auto mb-4"></div>
        <p className="font-bold text-slate-400 uppercase tracking-widest text-xs">Sincronizando Banco de Dados...</p>
      </div>
    </div>
  );

