import React, { useState, useEffect } from 'react';
import { PRICE_DISCOUNT, PIX_KEY } from '../constants';
import { PaymentMethod, Order, PaymentSettings } from '../types';
import { supabase } from '../lib/supabase';

interface CheckoutProps {
  onSuccess: (order: Order) => void;
  onCancel: () => void;
}

const Checkout: React.FC<CheckoutProps> = ({ onSuccess, onCancel }) => {
  const [step, setStep] = useState<1 | 2>(1);
  const [method, setMethod] = useState<PaymentMethod>('PIX');
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({ name: '', email: '', phone: '' });
  const [settings, setSettings] = useState<PaymentSettings>({
    pagbank_enabled: true,
    pix_enabled: true,
    api_key: '',
    pix_key: PIX_KEY,
    pix_qr_code: '',
    email_enabled: false,
    email_service_id: '',
    email_template_id: '',
    email_public_key: '',
    ebook_file_data: '',
    ebook_file_name: ''
  });

  useEffect(() => {
    async function loadSettings() {
      try {
        const { data, error } = await supabase
          .from('settings')
          .select('*')
          .eq('id', 1)
          .maybeSingle();

        if (data && !error) {
          setSettings(data);
          if (!data.pix_enabled && data.pagbank_enabled) setMethod('PAGBANK');
          else if (data.pix_enabled) setMethod('PIX');
        }
      } catch (err) {
        console.error("Erro ao carregar configurações:", err);
      }
    }
    loadSettings();
  }, []);

  const handleNext = (e: React.FormEvent) => {
    e.preventDefault();
    if (form.name.length < 3 || !form.email.includes('@')) {
      alert("Por favor, preencha seus dados corretamente.");
      return;
    }
    setStep(2);
  };

  const finishPayment = async () => {
    if (loading) return;

    if (!form.name || !form.email || !form.phone) {
      alert("Dados do cliente incompletos. Volte e preencha o formulário.");
      setStep(1);
      return;
    }

    setLoading(true);

    try {
      const orderId = Math.random().toString(36).substr(2, 6).toUpperCase();
      const newOrder: Order = {
        id: orderId,
        name: form.name.trim(),
        email: form.email.trim(),
        phone: form.phone.trim(),
        amount: PRICE_DISCOUNT,
        method: method,
        status: method === 'PAGBANK' ? 'PAID' : 'PENDING',
        date: new Date().toLocaleDateString('pt-BR'),
      };

      const { error } = await supabase
        .from('orders')
        .insert([newOrder])
        .select();

      if (error) throw error;

      onSuccess(newOrder);

    } catch (err: any) {
      console.error("Falha crítica no checkout:", err);
      alert('Erro ao processar: Verifique se as colunas (name, email, phone) existem na tabela orders do Supabase.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/95 z-[200] flex items-center justify-center p-2 md:p-4 backdrop-blur-md overflow-hidden">
      <div className="bg-white w-full max-w-xl max-h-[95vh] rounded-[2rem] md:rounded-[2.5rem] overflow-hidden shadow-2xl flex flex-col border-4 border-white animate-in zoom-in-95 duration-300">

        <div className="bg-blue-600 p-6 md:p-8 text-white flex justify-between items-center relative overflow-hidden flex-shrink-0">
          <div className="relative z-10">
             <h2 className="text-lg md:text-xl font-black uppercase tracking-tighter italic">Finalizar Pedido</h2>
             <p className="text-[9px] font-bold text-blue-200 uppercase tracking-widest">Ambiente Seguro</p>
          </div>
          <button onClick={onCancel} className="bg-white/10 hover:bg-white/20 p-2.5 rounded-full transition-all active:scale-90 z-10">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 md:p-10 space-y-6 md:space-y-8">
          {step === 1 ? (
            <form onSubmit={handleNext} className="space-y-5">
              <div className="flex items-center gap-3">
                 <div className="w-7 h-7 bg-blue-600 text-white rounded-full flex items-center justify-center font-black text-xs">1</div>
                 <h3 className="text-sm font-black text-slate-800 uppercase tracking-tight">Identificação</h3>
              </div>

              <div className="space-y-4">
                <input required type="text" placeholder="Nome Completo" className="w-full border-2 border-slate-100 bg-slate-50 rounded-xl p-4 outline-none focus:border-blue-500 transition-all font-medium" value={form.name} onChange={e => setForm({...form, name: e.target.value})} />
                <input required type="email" placeholder="E-mail para Entrega" className="w-full border-2 border-slate-100 bg-slate-50 rounded-xl p-4 outline-none focus:border-blue-500 transition-all font-medium" value={form.email} onChange={e => setForm({...form, email: e.target.value})} />
                <input required type="tel" placeholder="WhatsApp (DDD + Número)" className="w-full border-2 border-slate-100 bg-slate-50 rounded-xl p-4 outline-none focus:border-blue-500 transition-all font-medium" value={form.phone} onChange={e => setForm({...form, phone: e.target.value})} />
              </div>

              <button type="submit" className="w-full bg-blue-600 text-white font-black py-5 rounded-xl hover:bg-blue-700 transition-all uppercase tracking-widest text-xs shadow-lg shadow-blue-600/20 active:scale-[0.98]">
                Continuar para Pagamento
              </button>
            </form>
          ) : (
            <div className="space-y-6">
              <div className="flex items-center gap-3">
                 <div className="w-7 h-7 bg-blue-600 text-white rounded-full flex items-center justify-center font-black text-xs">2</div>
                 <h3 className="text-sm font-black text-slate-800 uppercase tracking-tight">Pagamento</h3>
              </div>

              <div className="grid grid-cols-2 gap-3">
                {settings.pix_enabled && (
                  <button onClick={() => setMethod('PIX')} className={`p-4 border-2 rounded-2xl flex flex-col items-center gap-2 transition-all relative ${method === 'PIX' ? 'border-blue-600 bg-blue-50/50' : 'border-slate-100'}`}>
                    <span className="text-2xl">⚡</span>
                    <span className="font-black text-[9px] uppercase tracking-widest text-slate-600">PIX</span>
                  </button>
                )}
                {settings.pagbank_enabled && (
                  <button onClick={() => setMethod('PAGBANK')} className={`p-4 border-2 rounded-2xl flex flex-col items-center gap-2 transition-all relative ${method === 'PAGBANK' ? 'border-blue-600 bg-blue-50/50' : 'border-slate-100'}`}>
                    <span className="text-2xl">💳</span>
                    <span className="font-black text-[9px] uppercase tracking-widest text-slate-600">Cartão</span>
                  </button>
                )}
              </div>

              <div className="animate-in fade-in zoom-in-95 duration-200">
                {method === 'PIX' ? (
                  <div className="bg-slate-50 p-5 rounded-[1.5rem] text-center space-y-4 border border-slate-100">
                    <div className="inline-block bg-white p-3 rounded-2xl shadow-md border border-slate-100">
                      {settings.pix_qr_code ? <img src={settings.pix_qr_code} className="w-36 h-36 mx-auto object-contain" /> : <div className="w-36 h-36 flex items-center justify-center text-[10px] text-gray-400 italic">Aguardando QR Code...</div>}
                    </div>
                    <div className="bg-white border border-slate-200 p-3 rounded-xl flex items-center justify-between text-[10px] font-mono">
                      <span className="truncate mr-4 text-slate-500">{settings.pix_key || PIX_KEY}</span>
                      <button onClick={() => {navigator.clipboard.writeText(settings.pix_key || PIX_KEY); alert('Copiado!');}} className="text-blue-600 font-bold uppercase shrink-0">Copiar</button>
                    </div>
                  </div>
                ) : (
                  <div className="bg-blue-50/50 p-6 rounded-[1.5rem] text-center border-2 border-blue-100">
                     <h4 className="font-black text-slate-800 text-xs uppercase">Cartão via PagBank</h4>
                     <p className="text-[10px] text-slate-500 leading-relaxed font-medium">Ambiente seguro de pagamento.</p>
                  </div>
                )}
              </div>

              <div className="flex flex-col md:flex-row gap-3 pt-2">
                <button disabled={loading} onClick={finishPayment} className="flex-[2] bg-green-600 text-white font-black py-5 rounded-xl uppercase text-xs tracking-widest active:scale-95 transition-all flex items-center justify-center gap-2">
                  {loading ? 'PROCESSANDO...' : 'CONFIRMAR PAGAMENTO'}
                </button>
                <button onClick={() => setStep(1)} className="flex-1 bg-slate-100 text-slate-500 font-black py-5 rounded-xl text-[10px] uppercase transition-all">Voltar</button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Checkout;

import React, { useState, useEffect } from 'react';
import { Order, PaymentSettings } from '../types';
import { PRODUCT_LINK, PIX_KEY } from '../constants';
import { supabase } from '../lib/supabase';

const Dashboard: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [activeTab, setActiveTab] = useState<'ORDERS' | 'SETTINGS'>('ORDERS');
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [filter, setFilter] = useState<string>('ALL');
  const [isSendingEmail, setIsSendingEmail] = useState<string | null>(null);

  const [settings, setSettings] = useState<PaymentSettings>({
    id: 1,
    pagbank_enabled: true,
    pix_enabled: true,
    api_key: '',
    pix_key: PIX_KEY,
    pix_qr_code: '',
    email_enabled: false,
    email_service_id: '',
    email_template_id: '',
    email_public_key: '',
    ebook_file_data: '',
    ebook_file_name: ''
  });

  useEffect(() => {
    loadAllData();
  }, []);

  async function loadAllData() {
    setLoading(true);
    try {
      const { data: ordersData } = await supabase
        .from('orders')
        .select('*')
        .order('id', { ascending: false });

      if (ordersData) setOrders(ordersData);

      const { data: settingsData } = await supabase
        .from('settings')
        .select('*')
        .eq('id', 1)
        .maybeSingle();

      if (settingsData) {
        setSettings(prev => ({ ...prev, ...settingsData }));
      }
    } catch (err) {
      console.error("Erro ao carregar dados:", err);
    } finally {
      setLoading(false);
    }
  }

  const saveSettings = async () => {
    setIsSaving(true);
    try {
      const { id, ...dataToSave } = settings;
      const { error } = await supabase
        .from('settings')
        .upsert({ id: 1, ...dataToSave }, { onConflict: 'id' });

      if (error) throw error;
      alert('Configurações salvas!');
    } catch (error: any) {
      console.error("Erro ao salvar:", error);
      alert('Erro ao salvar no banco: ' + error.message);
    } finally {
      setIsSaving(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, type: 'ebook' | 'pix') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (type === 'ebook') {
          setSettings(prev => ({ ...prev, ebook_file_data: reader.result as string, ebook_file_name: file.name }));
        } else {
          setSettings(prev => ({ ...prev, pix_qr_code: reader.result as string }));
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const updateStatus = async (id: string, status: Order['status']) => {
    const { error } = await supabase
      .from('orders')
      .update({ status })
      .eq('id', id);

    if (!error) {
      setOrders(orders.map(o => o.id === id ? { ...o, status } : o));
    }
  };

  const sendWhatsApp = (order: Order) => {
    const message = `Olá ${order.name}! Pagamento aprovado. Use o código #${order.id} no site para baixar seu guia no Pendrive Virtual.`;
    const url = `https://wa.me/55${order.phone.replace(/\D/g,'')}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
    updateStatus(order.id, 'SENT');
  };

  const sendEmail = async (order: Order) => {
    if (!settings.email_enabled || !settings.email_service_id) {
      alert("Configure o e-mail primeiro!");
      return;
    }
    setIsSendingEmail(order.id);
    try {
      const response = await fetch('https://api.emailjs.com/api/v1.0/email/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          service_id: settings.email_service_id,
          template_id: settings.email_template_id,
          user_id: settings.email_public_key,
          template_params: { to_name: order.name, to_email: order.email, order_id: order.id }
        })
      });
      if (response.ok) { alert(`E-mail enviado!`); updateStatus(order.id, 'SENT'); }
    } catch (error) { alert("Erro no envio."); } finally { setIsSendingEmail(null); }
  };

  const filteredOrders = orders.filter(o => filter === 'ALL' ? true : o.status === filter);

  if (loading) return <div className="min-h-screen bg-slate-50 flex items-center justify-center font-bold text-slate-400 italic tracking-widest">Sincronizando Banco...</div>;

  return (
    <div className="min-h-screen bg-slate-50 font-sans">
      <nav className="bg-slate-900 text-white p-4 flex flex-col md:flex-row justify-between items-center px-8 gap-4 shadow-xl">
        <h1 className="font-black text-xl tracking-tight">FLUXO LIMPO ADMIN</h1>
        <div className="flex bg-slate-800 p-1 rounded-xl">
          <button onClick={() => setActiveTab('ORDERS')} className={`px-6 py-2 rounded-lg text-xs font-bold ${activeTab === 'ORDERS' ? 'bg-blue-600 shadow-lg' : 'text-slate-400'}`}>VENDAS</button>
          <button onClick={() => setActiveTab('SETTINGS')} className={`px-6 py-2 rounded-lg text-xs font-bold ${activeTab === 'SETTINGS' ? 'bg-blue-600 shadow-lg' : 'text-slate-400'}`}>CONFIGURAÇÕES</button>
        </div>
        <button onClick={onClose} className="bg-red-500 hover:bg-red-600 text-white px-6 py-2 rounded-lg text-xs font-black transition-all">SAIR</button>
      </nav>

      <main className="max-w-7xl mx-auto p-4 md:p-8">
        {activeTab === 'ORDERS' ? (
          <div className="space-y-4">
             <div className="bg-white rounded-3xl shadow-sm border overflow-hidden">
                <table className="w-full text-left border-collapse min-w-[900px]">
                  <thead className="bg-slate-50 border-b">
                    <tr>
                      <th className="p-5 text-[10px] font-black uppercase text-slate-400 tracking-widest">ID / Data</th>
                      <th className="p-5 text-[10px] font-black uppercase text-slate-400 tracking-widest">Cliente</th>
                      <th className="p-5 text-[10px] font-black uppercase text-slate-400 tracking-widest text-center">Status</th>
                      <th className="p-5 text-[10px] font-black uppercase text-slate-400 tracking-widest text-right">Ações</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {filteredOrders.map(order => (
                      <tr key={order.id} className="hover:bg-blue-50/30 transition-colors text-sm">
                        <td className="p-5">
                          <span className="font-mono text-xs font-black bg-slate-100 px-2 py-1 rounded text-slate-600">#{order.id}</span>
                          <div className="text-[9px] text-slate-400 mt-1">{order.date}</div>
                        </td>
                        <td className="p-5">
                          <div className="font-bold">{order.name}</div>
                          <div className="text-[10px] text-slate-400">{order.email}</div>
                          <div className="text-[10px] text-blue-500 font-mono mt-0.5">{order.phone}</div>
                        </td>
                        <td className="p-5 text-center">
                          <select 
                            value={order.status} 
                            onChange={(e) => updateStatus(order.id, e.target.value as any)} 
                            className="text-[10px] font-black border rounded-xl px-3 py-1.5 outline-none bg-white shadow-sm"
                          >
                            <option value="PENDING">PENDENTE</option>
                            <option value="PAID">PAGO</option>
                            <option value="SENT">ENTREGUE</option>
                          </select>
                        </td>
                        <td className="p-5 text-right flex justify-end gap-2">
                          <button onClick={() => sendWhatsApp(order)} className="p-2.5 bg-green-500 text-white rounded-xl shadow-md hover:bg-green-600 active:scale-95 transition-all">
                            <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M.057 24l1.687-6.163c-1.041-1.804-1.588-3.849-1.587-5.946.003-6.556 5.338-11.891 11.893-11.891 3.181.001 6.167 1.24 8.413 3.488 2.246 2.248 3.484 5.232 3.483 8.413-.003 6.557-5.338 11.892-11.893 11.892-1.997-.001-3.951-.5-5.688-1.448l-6.308 1.654zm6.249-4.081c1.533.91 3.109 1.389 4.691 1.389 5.432.001 9.851-4.419 9.853-9.851.001-2.632-1.025-5.106-2.887-6.969-1.862-1.861-4.336-2.885-6.967-2.885-5.433 0-9.851 4.418-9.853 9.851-.001 1.734.456 3.426 1.321 4.9l-.83 3.033 3.102-.814zm11.378-7.514c-.301-.151-1.78-.878-2.057-.979-.277-.101-.478-.151-.679.151-.201.301-.778.979-.954 1.18-.176.202-.352.227-.653.076-.301-.151-1.272-.469-2.422-1.495-.894-.798-1.497-1.783-1.673-2.084-.176-.301-.019-.465.132-.614.135-.135.301-.351.452-.527.151-.176.201-.301.301-.502.101-.201.05-.377-.025-.527-.075-.151-.679-1.635-.93-2.239-.245-.588-.493-.508-.679-.518-.176-.008-.377-.01-.578-.01-.201 0-.527.075-.803.377-.276.301-1.054 1.03-1.054 2.513 0 1.482 1.079 2.912 1.23 3.113.151.201 2.124 3.243 5.145 4.544.718.309 1.28.494 1.716.632.723.23 1.381.197 1.9.12.579-.086 1.78-.728 2.031-1.431.251-.704.251-1.307.176-1.432-.075-.125-.276-.201-.577-.352z"/></svg>
                          </button>
                          <button onClick={() => sendEmail(order)} className="p-2.5 bg-blue-500 text-white rounded-xl shadow-md hover:bg-blue-600 active:scale-95 transition-all">
                            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 8l7.89 5.26a2 2 0 002.22 0L21 8M5 19h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z"/></svg>
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
             </div>
          </div>
        ) : (
          <div className="max-w-4xl mx-auto space-y-8 pb-20">
            <section className="bg-white p-8 rounded-[2rem] border-2 border-slate-100">
              <h3 className="font-black mb-6">Gateway e PIX</h3>
              <div className="space-y-4">
                <input type="password" value={settings.api_key} onChange={e => setSettings({...settings, api_key: e.target.value})} className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm" placeholder="PagBank Token" />
                <input type="text" value={settings.pix_key} onChange={e => setSettings({...settings, pix_key: e.target.value})} className="w-full border-2 border-slate-100 rounded-2xl p-4 text-sm" placeholder="Chave PIX" />
                <input type="file" onChange={(e) => handleFileUpload(e, 'pix')} className="text-xs" />
              </div>
            </section>

            <section className="bg-white p-8 rounded-[2rem] border-2 border-slate-100">
              <h3 className="font-black mb-6">Arquivo do Produto</h3>
              <input type="file" onChange={(e) => handleFileUpload(e, 'ebook')} className="text-xs" />
              {settings.ebook_file_name && <p className="text-[10px] mt-2 text-green-600 font-bold">{settings.ebook_file_name}</p>}
            </section>

            <button disabled={isSaving} onClick={saveSettings} className="w-full bg-blue-600 text-white font-black py-6 rounded-[2rem] shadow-xl hover:bg-blue-700 active:scale-95 transition-all">
              {isSaving ? 'SALVANDO...' : 'SALVAR CONFIGURAÇÕES'}
            </button>
          </div>
        )}
      </main>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { Order, PaymentSettings } from '../types';
import { PIX_KEY, PRODUCT_LINK } from '../constants';
import { supabase } from '../lib/supabase';

const OrderTracker: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [orderId, setOrderId] = useState('');
  const [loading, setLoading] = useState(false);
  const [foundOrder, setFoundOrder] = useState<Order | null>(null);
  const [error, setError] = useState('');
  const [settings, setSettings] = useState<PaymentSettings>({
    pagbank_enabled: true,
    pix_enabled: true,
    api_key: '',
    pix_key: PIX_KEY,
    pix_qr_code: '',
    email_enabled: false,
    email_service_id: '',
    email_template_id: '',
    email_public_key: '',
    ebook_file_data: '',
    ebook_file_name: ''
  });

  useEffect(() => {
    async function loadSettings() {
      const { data } = await supabase.from('settings').select('*').eq('id', 1).maybeSingle();
      if (data) setSettings(data);
    }
    loadSettings();
  }, []);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    const cleanId = orderId.replace('#', '').trim().toUpperCase();

    const { data, error: sbError } = await supabase
      .from('orders')
      .select('*')
      .eq('id', cleanId)
      .maybeSingle();

    if (data && !sbError) {
      setFoundOrder(data);
    } else {
      setFoundOrder(null);
      setError('Pedido não encontrado.');
    }
    setLoading(false);
  };

  const handleDownload = () => {
    const link = document.createElement('a');
    link.href = settings.ebook_file_data || PRODUCT_LINK;
    link.download = settings.ebook_file_name || "Guia-Alugueis-2026.pdf";
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="fixed inset-0 bg-slate-900/95 z-[250] flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white w-full max-w-lg rounded-[2.5rem] overflow-hidden shadow-2xl border-4 border-white animate-in zoom-in-95 duration-300">
        <div className="bg-slate-800 p-6 text-white flex justify-between items-center">
          <h2 className="font-bold flex items-center gap-2">Seu Armazenamento Seguro</h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-white/10">✕</button>
        </div>

        <div className="p-8">
          {!foundOrder ? (
            <form onSubmit={handleSearch} className="space-y-4">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1 block">Insira o código do pedido</label>
              <input required type="text" placeholder="Ex: #A1B2C3" className="w-full border-2 bg-slate-50 rounded-2xl p-4 font-mono font-bold outline-none focus:border-blue-500 transition-all uppercase" value={orderId} onChange={e => setOrderId(e.target.value)} />
              {error && <p className="text-red-500 text-xs font-bold text-center">{error}</p>}
              <button disabled={loading} className="w-full bg-blue-600 text-white font-black py-5 rounded-2xl shadow-xl hover:bg-blue-700 active:scale-95 transition-all">
