Você deve copiar este código, ir ao painel do **Supabase -> SQL Editor -> New Query**, colar e clicar em **Run**.

### Script SQL para Reconstrução do Banco

```sql
-- 1. Limpar tabelas existentes (CUIDADO: Isso apaga os dados atuais)
DROP TABLE IF EXISTS orders;
DROP TABLE IF EXISTS settings;
DROP TABLE IF EXISTS admins;

-- 2. Criar tabela de Pedidos (Orders)
CREATE TABLE orders (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    email TEXT NOT NULL,
    phone TEXT NOT NULL,
    amount TEXT NOT NULL,
    method TEXT NOT NULL, -- 'PIX' ou 'PAGBANK'
    status TEXT NOT NULL DEFAULT 'PENDING', -- 'PENDING', 'PAID', 'SENT'
    date TEXT NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- 3. Criar tabela de Configurações (Settings)
CREATE TABLE settings (
    id BIGINT PRIMARY KEY,
    pagbank_enabled BOOLEAN DEFAULT TRUE,
    pix_enabled BOOLEAN DEFAULT TRUE,
    api_key TEXT DEFAULT '',
    pix_key TEXT DEFAULT 'financeiro@guiadealuguel.com.br',
    pix_qr_code TEXT DEFAULT '',
    email_enabled BOOLEAN DEFAULT FALSE,
    email_service_id TEXT DEFAULT '',
    email_template_id TEXT DEFAULT '',
    email_public_key TEXT DEFAULT '',
    ebook_file_data TEXT DEFAULT '',
    ebook_file_name TEXT DEFAULT '',
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- 4. Criar tabela de Administradores (Admins)
CREATE TABLE admins (
    id BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
    email TEXT UNIQUE NOT NULL,
    password TEXT NOT NULL,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- 5. Inserir Configuração Inicial (ID 1 é obrigatório para o app funcionar)
INSERT INTO settings (id, pix_key) VALUES (1, 'financeiro@guiadealuguel.com.br');

-- 6. Inserir Administrador Padrão (Você pode alterar a senha depois no painel)
INSERT INTO admins (email, password) VALUES ('admin@admin.com', 'admin123');

-- 7. Habilitar RLS (Segurança básica para permitir inserts e selects simples)
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE settings ENABLE ROW LEVEL SECURITY;
ALTER TABLE admins ENABLE ROW LEVEL SECURITY;

-- 8. Criar Políticas de Acesso
CREATE POLICY "Permitir inserts públicos em orders" ON orders FOR INSERT WITH CHECK (true);
CREATE POLICY "Permitir consulta pública por ID em orders" ON orders FOR SELECT USING (true);
CREATE POLICY "Permitir leitura pública de settings" ON settings FOR SELECT USING (true);
CREATE POLICY "Permitir tudo para admin autenticado em orders" ON orders FOR ALL USING (true);
CREATE POLICY "Permitir tudo para admin autenticado em settings" ON settings FOR ALL USING (true);
CREATE POLICY "Permitir leitura de admins para login" ON admins FOR SELECT USING (true);
```

